// // This module generates a one-bit constant that outputs a logic LOW when the clock enable (ce) signal is asserted, and resets to logic HIGH when the clear (clr) signal is activated.
module top_module(
  output [(1 - 1):0] op,
  input clk,
  input ce,
  input clr
);reg [(1 - 1):0] op_reg;

  always @(posedge clk) begin
    if (clr) begin
      op_reg <= 1'b0;
    end else if (ce) begin
      op_reg <= 1'b1;
    end
  end

  assign op = op_reg;
endmodule
